6986 ConstantRange ScalarEvolution::getRangeForAffineNoSelfWrappingAR(
6987     const SCEVAddRecExpr *AddRec, const SCEV *MaxBECount, unsigned BitWidth,
6988     ScalarEvolution::RangeSignHint SignHint) {
6989   assert(AddRec->isAffine() && "Non-affine AddRecs are not suppored!\n");
6990   assert(AddRec->hasNoSelfWrap() &&
6991          "This only works for non-self-wrapping AddRecs!");
6992   const bool IsSigned = SignHint == HINT_RANGE_SIGNED;
6993   const SCEV *Step = AddRec->getStepRecurrence(*this);
6994   // Only deal with constant step to save compile time.
6995   if (!isa<SCEVConstant>(Step))
6996     return ConstantRange::getFull(BitWidth);
6997   // Let's make sure that we can prove that we do not self-wrap during
6998   // MaxBECount iterations. We need this because MaxBECount is a maximum
6999   // iteration count estimate, and we might infer nw from some exit for which we
7000   // do not know max exit count (or any other side reasoning).
7001   // TODO: Turn into assert at some point.
7002   if (getTypeSizeInBits(MaxBECount->getType()) >
7003       getTypeSizeInBits(AddRec->getType()))
7004     return ConstantRange::getFull(BitWidth);
7005   MaxBECount = getNoopOrZeroExtend(MaxBECount, AddRec->getType());
7006   const SCEV *RangeWidth = getMinusOne(AddRec->getType());
7007   const SCEV *StepAbs = getUMinExpr(Step, getNegativeSCEV(Step));
7008   const SCEV *MaxItersWithoutWrap = getUDivExpr(RangeWidth, StepAbs);
7009   if (!isKnownPredicateViaConstantRanges(ICmpInst::ICMP_ULE, MaxBECount,
7010                                          MaxItersWithoutWrap))
7011     return ConstantRange::getFull(BitWidth);
7012 
7013   ICmpInst::Predicate LEPred =
7014       IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
7015   ICmpInst::Predicate GEPred =
7016       IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
7017   const SCEV *End = AddRec->evaluateAtIteration(MaxBECount, *this);
7018 
7019   // We know that there is no self-wrap. Let's take Start and End values and
7020   // look at all intermediate values V1, V2, ..., Vn that IndVar takes during
7021   // the iteration. They either lie inside the range [Min(Start, End),
7022   // Max(Start, End)] or outside it:
7023   //
7024   // Case 1:   RangeMin    ...    Start V1 ... VN End ...           RangeMax;
7025   // Case 2:   RangeMin Vk ... V1 Start    ...    End Vn ... Vk + 1 RangeMax;
7026   //
7027   // No self wrap flag guarantees that the intermediate values cannot be BOTH
7028   // outside and inside the range [Min(Start, End), Max(Start, End)]. Using that
7029   // knowledge, let's try to prove that we are dealing with Case 1. It is so if
7030   // Start <= End and step is positive, or Start >= End and step is negative.
7031   const SCEV *Start = applyLoopGuards(AddRec->getStart(), AddRec->getLoop());
7032   ConstantRange StartRange = getRangeRef(Start, SignHint);
7033   ConstantRange EndRange = getRangeRef(End, SignHint);
7034   ConstantRange RangeBetween = StartRange.unionWith(EndRange);
7035   // If they already cover full iteration space, we will know nothing useful
7036   // even if we prove what we want to prove.
7037   if (RangeBetween.isFullSet())
7038     return RangeBetween;
7039   // Only deal with ranges that do not wrap (i.e. RangeMin < RangeMax).
7040   bool IsWrappedSet = IsSigned ? RangeBetween.isSignWrappedSet()
7041                                : RangeBetween.isWrappedSet();
7042   if (IsWrappedSet)
7043     return ConstantRange::getFull(BitWidth);
7044 
7045   if (isKnownPositive(Step) &&
7046       isKnownPredicateViaConstantRanges(LEPred, Start, End))
7047     return RangeBetween;
7048   if (isKnownNegative(Step) &&
7049            isKnownPredicateViaConstantRanges(GEPred, Start, End))
7050     return RangeBetween;
7051   return ConstantRange::getFull(BitWidth);
7052 }
