7054 ConstantRange ScalarEvolution::getRangeViaFactoring(const SCEV *Start,
7055                                                     const SCEV *Step,
7056                                                     const APInt &MaxBECount) {
7057   //    RangeOf({C?A:B,+,C?P:Q}) == RangeOf(C?{A,+,P}:{B,+,Q})
7058   // == RangeOf({A,+,P}) union RangeOf({B,+,Q})
7059 
7060   unsigned BitWidth = MaxBECount.getBitWidth();
7061   assert(getTypeSizeInBits(Start->getType()) == BitWidth &&
7062          getTypeSizeInBits(Step->getType()) == BitWidth &&
7063          "mismatched bit widths");
7064 
7065   struct SelectPattern {
7066     Value *Condition = nullptr;
7067     APInt TrueValue;
7068     APInt FalseValue;
7069 
7070     explicit SelectPattern(ScalarEvolution &SE, unsigned BitWidth,
7071                            const SCEV *S) {
7072       std::optional<unsigned> CastOp;
7073       APInt Offset(BitWidth, 0);
7074 
7075       assert(SE.getTypeSizeInBits(S->getType()) == BitWidth &&
7076              "Should be!");
7077 
7078       // Peel off a constant offset:
7079       if (auto *SA = dyn_cast<SCEVAddExpr>(S)) {
7080         // In the future we could consider being smarter here and handle
7081         // {Start+Step,+,Step} too.
7082         if (SA->getNumOperands() != 2 || !isa<SCEVConstant>(SA->getOperand(0)))
7083           return;
7084 
7085         Offset = cast<SCEVConstant>(SA->getOperand(0))->getAPInt();
7086         S = SA->getOperand(1);
7087       }
7088 
7089       // Peel off a cast operation
7090       if (auto *SCast = dyn_cast<SCEVIntegralCastExpr>(S)) {
7091         CastOp = SCast->getSCEVType();
7092         S = SCast->getOperand();
7093       }
7094 
7095       using namespace llvm::PatternMatch;
7096 
7097       auto *SU = dyn_cast<SCEVUnknown>(S);
7098       const APInt *TrueVal, *FalseVal;
7099       if (!SU ||
7100           !match(SU->getValue(), m_Select(m_Value(Condition), m_APInt(TrueVal),
7101                                           m_APInt(FalseVal)))) {
7102         Condition = nullptr;
7103         return;
7104       }
7105 
7106       TrueValue = *TrueVal;
7107       FalseValue = *FalseVal;
7108 
7109       // Re-apply the cast we peeled off earlier
7110       if (CastOp)
7111         switch (*CastOp) {
7112         default:
7113           llvm_unreachable("Unknown SCEV cast type!");
7114 
7115         case scTruncate:
7116           TrueValue = TrueValue.trunc(BitWidth);
7117           FalseValue = FalseValue.trunc(BitWidth);
7118           break;
7119         case scZeroExtend:
7120           TrueValue = TrueValue.zext(BitWidth);
7121           FalseValue = FalseValue.zext(BitWidth);
7122           break;
7123         case scSignExtend:
7124           TrueValue = TrueValue.sext(BitWidth);
7125           FalseValue = FalseValue.sext(BitWidth);
7126           break;
7127         }
7128 
7129       // Re-apply the constant offset we peeled off earlier
7130       TrueValue += Offset;
7131       FalseValue += Offset;
7132     }
7133 
7134     bool isRecognized() { return Condition != nullptr; }
7135   };
7136 
7137   SelectPattern StartPattern(*this, BitWidth, Start);
7138   if (!StartPattern.isRecognized())
7139     return ConstantRange::getFull(BitWidth);
7140 
7141   SelectPattern StepPattern(*this, BitWidth, Step);
7142   if (!StepPattern.isRecognized())
7143     return ConstantRange::getFull(BitWidth);
7144 
7145   if (StartPattern.Condition != StepPattern.Condition) {
7146     // We don't handle this case today; but we could, by considering four
7147     // possibilities below instead of two. I'm not sure if there are cases where
7148     // that will help over what getRange already does, though.
7149     return ConstantRange::getFull(BitWidth);
7150   }
7151 
7152   // NB! Calling ScalarEvolution::getConstant is fine, but we should not try to
7153   // construct arbitrary general SCEV expressions here.  This function is called
7154   // from deep in the call stack, and calling getSCEV (on a sext instruction,
7155   // say) can end up caching a suboptimal value.
7156 
7157   // FIXME: without the explicit `this` receiver below, MSVC errors out with
7158   // C2352 and C2512 (otherwise it isn't needed).
7159 
7160   const SCEV *TrueStart = this->getConstant(StartPattern.TrueValue);
7161   const SCEV *TrueStep = this->getConstant(StepPattern.TrueValue);
7162   const SCEV *FalseStart = this->getConstant(StartPattern.FalseValue);
7163   const SCEV *FalseStep = this->getConstant(StepPattern.FalseValue);
7164 
7165   ConstantRange TrueRange =
7166       this->getRangeForAffineAR(TrueStart, TrueStep, MaxBECount);
7167   ConstantRange FalseRange =
7168       this->getRangeForAffineAR(FalseStart, FalseStep, MaxBECount);
7169 
7170   return TrueRange.unionWith(FalseRange);
7171 }
